d3 = require("d3@7")
langs = transpose(lang_stats)
// the language bubble pack ("snail") from the original wordbank home page:
// one bubble per language, area ~ n_children^0.65, HCL rainbow by size rank
{
  const width = 640, height = 560;

  const root = d3.pack()
    .size([width, height])
    .padding(5)(
      d3.hierarchy({ children: langs })
        .sum((d) =&gt; Math.pow(d.count, 0.65))
        .sort((a, b) =&gt; b.value - a.value)
    );

  const color = new Map(langs.map((d, i) =&gt;
    [d.name, d3.hcl((i * 360 / langs.length) % 360, 60, 60).formatHex()]));

  const svg = d3.create("svg")
    .attr("viewBox", [0, 0, width, height])
    .attr("style", "max-width: 100%; height: auto; display: block; margin: 0 auto;");

  const node = svg.selectAll("g")
    .data(root.leaves())
    .join("g")
    .attr("transform", (d) =&gt; `translate(${d.x},${d.y})`);

  node.append("circle")
    .attr("r", (d) =&gt; d.r)
    .attr("fill", (d) =&gt; color.get(d.data.name));

  node.append("title")
    .text((d) =&gt; `${d.data.language}: ${d.data.count.toLocaleString()} children`);

  // fit label to bubble (same rule as the original: min(2r, scaled-to-width)),
  // measuring text with a canvas so the svg never needs to touch the DOM
  const ctx = document.createElement("canvas").getContext("2d");
  ctx.font = "12px sans-serif";
  const fontSize = (d) =&gt; {
    const w = ctx.measureText(d.data.name).width;
    return Math.max(0, Math.min(2 * d.r, (2 * d.r - 8) / w * 12));
  };

  node.append("text")
    .attr("dy", ".35em")
    .attr("text-anchor", "middle")
    .attr("fill", "white")
    .attr("style", "font-family: var(--sans-serif); pointer-events: none;")
    .style("font-size", (d) =&gt; fontSize(d) + "px")
    .text((d) =&gt; d.data.name);

  return svg.node();
}

Explore how individual words are acquired over development. Pick a language and form, select words, and optionally split by a demographic variable — proportions are computed in your browser from the raw child-by-word responses.

san = (s) =&gt; s.toLowerCase().replace(/[^a-z0-9]+/g, "_").replace(/^_+|_+$/g, "")

split_options = new Map([
  ["None", null],
  ["Sex", "sex"],
  ["Birth order", "birth_order"],
  ["Caregiver education", "caregiver_education"],
  ["Ethnicity", "ethnicity"]
])

level_orders = ({
  sex: ["Female", "Male", "Other"],
  birth_order: ["First", "Second", "Third", "Fourth", "Fifth", "Sixth",
                "Seventh", "Eighth"],
  caregiver_education: ["None", "Primary", "Some Secondary", "Secondary",
                        "Some College", "College", "Some Graduate", "Graduate"],
  ethnicity: ["Asian", "Black", "Hispanic", "White", "Other"]
})

level_sort = (split) =&gt; {
  const order = split ? (level_orders[split] ?? []) : [];
  return (a, b) =&gt; {
    const ia = order.indexOf(a), ib = order.indexOf(b);
    if (ia !== -1 || ib !== -1) return (ia === -1 ? 99 : ia) - (ib === -1 ? 99 : ib);
    return a &lt; b ? -1 : a &gt; b ? 1 : 0;
  };
}






























download_csv = (rows, filename) =&gt; {
  if (!rows || !rows.length) return html`&lt;span&gt;&lt;/span&gt;`;
  const cols = Object.keys(rows[0]);
  const esc = (v) =&gt; {
    const s = String(v ?? "");
    return /[",\n]/.test(s) ? '"' + s.replace(/"/g, '""') + '"' : s;
  };
  const csv = [cols.join(","), ...rows.map((r) =&gt; cols.map((c) =&gt; esc(r[c])).join(","))].join("\n");
  const url = URL.createObjectURL(new Blob([csv], { type: "text/csv" }));
  return html`&lt;a class="btn btn-sm btn-outline-primary" href=${url} download=${filename}&gt;Download CSV&lt;/a&gt;`;
}







Plot = import("https://esm.sh/@observablehq/plot@0.6.17")
duckdb = import("https://cdn.jsdelivr.net/npm/@duckdb/duckdb-wasm@1.29.0/+esm")

db = {
  const bundle = await duckdb.selectBundle(duckdb.getJsDelivrBundles());
  const worker = await duckdb.createWorker(bundle.mainWorker);
  const database = new duckdb.AsyncDuckDB(new duckdb.VoidLogger(), worker);
  await database.instantiate(bundle.mainModule, bundle.pthreadWorker);
  return database;
}
conn = db.connect()
registered = new Set()

insts = transpose(instruments)
languages = [...new Set(insts.map((d) =&gt; d.language))].sort()

sql = async (q) =&gt; (await (await conn).query(q)).toArray().map((r) =&gt; ({...r.toJSON()}))
quote_list = (xs) =&gt; xs.map((x) =&gt; `'${String(x).replace(/'/g, "''")}'`).join(", ")



































































viewof language = Inputs.select(languages, {
  label: "Language",
  value: "English (American)"
})
viewof form = Inputs.select(
  insts.filter((d) =&gt; d.language === language).map((d) =&gt; d.form),
  { label: "Form" }
)
















resp = {
  const slug = san(language + " " + form);
  const fname = `${slug}.parquet`;
  if (!registered.has(fname)) {
    const buf = new Uint8Array(
      await fetch(`slices/responses/${fname}`).then((r) =&gt; {
        if (!r.ok) throw new Error(`no data for ${language} ${form}`);
        return r.arrayBuffer();
      }));
    await db.registerFileBuffer(fname, buf);
    registered.add(fname);
  }
  return `read_parquet('${fname}')`;
}

form_type = insts.find((d) =&gt; d.language === language && d.form === form)?.form_type
measures = form_type === "WG" ? ["produces", "understands"] : ["produces"]
words = (await sql(`SELECT DISTINCT item_definition FROM ${resp} WHERE item_kind = 'word' ORDER BY 1`))
  .map((d) =&gt; d.item_definition)
default_words = {
  const defaults = words.filter((w) =&gt; ["dog", "mommy*", "ball"].includes(w));
  return defaults.length ? defaults : words.slice(0, 3);
}





































viewof measure = Inputs.select(measures, { label: "Measure" })
viewof selected = Inputs.select(words, {
  label: "Words",
  multiple: 8,
  value: default_words
})
viewof split = Inputs.select(split_options, { label: "Split by" })
viewof norming_only = Inputs.toggle({ label: "Norming data only", value: false })
































min_n_traj = 5
trajectory_data = {
  if (!selected.length) return [];
  const grp = split ? `CAST(${split} AS VARCHAR)` : `'All data'`;
  const where = [
    `item_kind = 'word'`,
    `item_definition IN (${quote_list(selected)})`,
    split ? `${grp} IS NOT NULL AND ${grp} &lt;&gt; ''` : `TRUE`,
    norming_only ? `is_norming` : `TRUE`
  ].join(" AND ");
  const rows = await sql(`
    SELECT item_definition, ${grp} AS grp, age,
           AVG(CASE WHEN ${measure} THEN 1.0 ELSE 0.0 END) AS prop,
           COUNT(DISTINCT data_id)::INT AS n_children
    FROM ${resp}
    WHERE ${where}
    GROUP BY 1, 2, 3
    HAVING COUNT(DISTINCT data_id) &gt;= ${min_n_traj}
    ORDER BY 1, 2, 3`);
  return rows.map((d) =&gt; ({ ...d, age: Number(d.age), prop: Number(d.prop),
                            n_children: Number(d.n_children) }));
}

traj_groups = [...new Set(trajectory_data.map((d) =&gt; d.grp))].sort(level_sort(split))























{
  if (!trajectory_data.length) {
    return html`&lt;em&gt;No data for this selection (age-by-group cells need at least ${min_n_traj} children).&lt;/em&gt;`;
  }
  const single = traj_groups.length === 1;
  const panels = traj_groups.map((g) =&gt; {
    const sub = trajectory_data.filter((d) =&gt; d.grp === g);
    return html`&lt;div style="text-align:center"&gt;
      ${single ? "" : html`&lt;div style="font-weight:600"&gt;${g}&lt;/div&gt;`}
      ${Plot.plot({
        style: { fontFamily: "var(--sans-serif)", fontSize: single ? "13px" : "11px" },
        width: single ? 850 : 410,
        height: single ? 450 : 300,
        inset: 8,
        grid: true,
        x: { label: "Age (months)", tickFormat: "d" },
        y: { label: single ? `Proportion of children who ${measure === "produces" ? "produce" : "understand"}` : null, domain: [0, 1] },
        color: { legend: single, domain: selected },
        marks: [
          Plot.dot(sub, {
            x: "age", y: "prop", stroke: "item_definition",
            r: (d) =&gt; Math.sqrt(d.n_children) / 4, fillOpacity: 0.5,
            channels: { n_children: "n_children" }, tip: true
          }),
          Plot.lineY(sub, Plot.windowY(
            { k: 3, reduce: "mean" },
            { x: "age", y: "prop", stroke: "item_definition", curve: "basis", strokeWidth: 2.5 }
          ))
        ]
      })}
    &lt;/div&gt;`;
  });
  return html`&lt;div style="display:flex;flex-wrap:wrap;gap:12px"&gt;
    ${single ? "" : html`&lt;div style="width:100%"&gt;${Plot.legend({ color: { domain: selected } })}&lt;/div&gt;`}
    ${panels}
  &lt;/div&gt;`;
}







Inputs.table(
  trajectory_data.map(({ item_definition, grp, age, n_children, prop }) =&gt;
    ({ word: item_definition, group: grp, age, n: n_children,
       proportion: Math.round(prop * 1e4) / 1e4 })),
  { maxWidth: 900 }
)







download_csv(trajectory_data, `wordbank_trajectories_${san(language + " " + form)}_${measure}.csv`)

