index = d3.json("slices/unilemmas/index.json")
lemma_opts = new Map(index.map((d) =&gt; [`${d.uni_lemma} (${d.n_languages} languages)`, d]))
sex_colors = new Map([["All", "#337ab7"], ["Female", "#c2571a"], ["Male", "#3b8462"]])







































viewof lemma = Inputs.select(lemma_opts, {
  label: "Uni-lemma",
